def predict(triples: list) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    # Convert tuples to Triple objects if needed
    processed_triples = []
    for t in triples:
        if isinstance(t, Triple):
            processed_triples.append(t)
        else:
            # Handle tuple format: (subject, predicate, object)
            processed_triples.append(Triple(subject=t[0], predicate=t[1], object=t[2]))

    if not processed_triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Helper to build a clause for a single triple
    def _clause(s: str, p: str, o: str) -> str:
        # Primary airport‑specific predicates
        if p == "cityServed":
            return f"{s} serves the city of {o}"
        if p == "location":
            return f"{s} is located in {o}"
        if p == "country":
            return f"{s} is in {o}"
        if p == "isPartOf":
            return f"{s} is part of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"{s} lies at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"{s} lies at an elevation of {o} feet above sea level"
        if p == "elevationAboveTheSeaLevelInMetres":
            return f"{s} lies at an elevation of {o} metres above sea level"
        if p == "operatingOrganisation":
            return f"{s} is operated by {o}"
        if p == "runwaySurfaceType":
            return f"{s} has a runway surface of {o}"
        # Runway length variants
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} feet long"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} metres long"
        # Runway identifiers
        if p == "runwayName":
            return f"{s}'s runway is named {o}"
        if p == "runwayLength":
            return f"{s}'s runway length is {o}"
        # Runway surface types
        if p.endswith("RunwaySurfaceType"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway surface is {o}"
        # Runway numbers
        if p.endswith("RunwayNumber"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway number is {o}"
        # Aviation codes
        if p == "iataLocationIdentifier":
            return f"{s} has IATA code {o}"
        if p == "icaoLocationIdentifier":
            return f"{s} has ICAO code {o}"
        if p == "locationIdentifier":
            return f"{s} has location identifier {o}"
        # Ownership and administration
        if p == "owner":
            return f"{s} is owned by {o}"
        if p == "largestCity":
            return f"The largest city of {s} is {o}"
        if p == "capital":
            return f"The capital of {s} is {o}"
        if p == "language" or p == "officialLanguage":
            return f"The official language of {s} is {o}"
        if p == "leader":
            return f"The leader of {s} is {o}"
        if p == "leaderTitle":
            return f"The leader title of {s} is {o}"
        if p == "leaderParty":
            return f"The leader of {s} belongs to the {o} party"
        # Native name
        if p == "nativeName":
            return f"{s} is known as {o}"
        # Administrative info
        if p == "administrativeArrondissement":
            return f"{s} is in the administrative arrondissement of {o}"
        if p == "mayor":
            return f"The mayor of {s} is {o}"
        if p == "currency":
            return f"{s} uses the {o}"
        if p == "demonym":
            return f"People from {s} are called {o}"
        if p == "regionServed":
            return f"{s} serves the {o} region"
        if p == "hubAirport":
            return f"{o} is a hub airport for {s}"
        if p == "headquarter":
            return f"{s} has its headquarters at {o}"
        if p == "foundedBy":
            return f"{s} was founded by {o}"
        if p == "foundingYear":
            return f"{s} was founded in {o}"
        if p == "postalCode":
            return f"{s} has postal code {o}"
        if p == "areaCode":
            return f"{s} has area code {o}"
        if p == "ceremonialCounty":
            return f"{s} is in the ceremonial county of {o}"
        if p == "countySeat":
            return f"The county seat of {s} is {o}"
        if p == "chief":
            return f"The chief of {s} is {o}"
        if p == "jurisdiction":
            return f"{s} has jurisdiction over {o}"
        if p == "city":
            return f"{s} is located in {o}"
        # Fallback for any other predicate
        return f"{s} has {p} {o}"

    # Build clauses with metadata for better joining
    clause_data = []
    for t in processed_triples:
        clause = _clause(t.subject, t.predicate, _clean(t.object))
        clause_data.append({
            'clause': clause,
            'subject': t.subject,
            'predicate': t.predicate,
            'object': _clean(t.object)
        })

    # Build a sentence by connecting related entities
    if len(clause_data) == 1:
        return clause_data[0]['clause'] + "."

    # Group clauses by subject to find related entities
    subject_groups = {}
    for cd in clause_data:
        subj = cd['subject']
        if subj not in subject_groups:
            subject_groups[subj] = []
        subject_groups[subj].append(cd)

    # Start with the first subject's main clause
    main_subject = clause_data[0]['subject']
    main_clauses = subject_groups.get(main_subject, [])

    # Find other subjects that are mentioned in objects
    related_subjects = []
    for cd in clause_data:
        if cd['subject'] != main_subject and cd['subject'] in cd['object']:
            related_subjects.append(cd['subject'])

    # Build the sentence by chaining related information
    parts = []

    # Add main subject clauses
    for i, cd in enumerate(main_clauses):
        if i == 0:
            parts.append(cd['clause'])
        else:
            # Add additional clauses for same subject with "and"
            parts.append(" and " + cd['clause'].lower())

    # Add related information using relative clauses
    for cd in clause_data:
        if cd['subject'] != main_subject:
            # Check if this subject is referenced in the object of another clause
            is_referenced = any(main_subject in cd['object'] or cd['subject'] in main_clauses[0]['object']
                              for mc in main_clauses)

            if is_referenced or cd['subject'] == main_clauses[0]['object']:
                # Create relative clause
                clause_text = cd['clause']
                # Remove the subject from the beginning
                rest = clause_text.replace(cd['subject'], "", 1).strip()
                rest = rest[0].upper() + rest[1:] if rest else ""
                parts.append(", which " + rest.lower())
            else:
                # Add as separate clause
                parts.append(", " + cd['clause'].lower())

    # Clean up and format the sentence
    sentence = "".join(parts)

    # Fix double spaces and ensure proper punctuation
    import re
    sentence = re.sub(r'\s+', ' ', sentence)
    sentence = sentence.strip()

    # Ensure sentence ends with period
    if not sentence.endswith('.'):
        sentence += '.'

    # Capitalize first character
    return sentence[0].upper() + sentence[1:]

